const Ht={className:"PosterizeBlock",emit(e,r,t,o,f){const c=f.resolve(e,"value",t,o),s=f.cast(f.resolve(e,"steps",t,o),c.type).expr,i=`(${(e=>{if("f32"===e)return"1.0";if("vec2f"===e)return"vec2<f32>(1.0)";if("vec3f"===e)return"vec3<f32>(1.0)";if("vec4f"===e)return"vec4<f32>(1.0)";throw Error("NodeMaterial:PosterizeBlock does not support "+e);})(c.type)}/${s})`;return{expr:`(floor(${c.expr}/${i})*${i})`,type:c.type};}};export{Ht as emitter};